def assess(record: dict) -> str:
    required = {'case_id', 'known_steps', 'branch_count', 'tool_choice_uncertain', 'baseline_success', 'agent_success'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (not record["known_steps"] or record["agent_success"] > record["baseline_success"])) else "KEEP_DETERMINISTIC_WORKFLOW"

